import React, { useState } from "react";
import Dice from "react-dice-roll";

// --- Board image ---
const boardImage = "/torahpoly_board.png"; // must be in public folder

// --- Constants ---
const TOTAL_SPACES = 44; // 11 per side x 4 sides
const BOARD_SIZE = 800; // base pixel reference for coordinate generation

// Generate 44 approximate positions (11 per side)
const generateBoardPositions = (size) => {
  const positions = [];
  const padding = 40;
  const inner = size - 2 * padding;
  const step = inner / 10; // 11 spaces → 10 steps per side

  // Bottom row (right → left)
  for (let i = 0; i < 11; i++) {
    positions.push({ x: size - padding - i * step, y: size - padding });
  }
  // Left column (bottom → top)
  for (let i = 1; i < 11; i++) {
    positions.push({ x: padding, y: size - padding - i * step });
  }
  // Top row (left → right)
  for (let i = 1; i < 11; i++) {
    positions.push({ x: padding + i * step, y: padding });
  }
  // Right column (top → bottom)
  for (let i = 1; i < 11; i++) {
    positions.push({ x: size - padding, y: padding + i * step });
  }

  return positions;
};

const App = () => {
  const [playerPosition, setPlayerPosition] = useState(0);
  const [rolling, setRolling] = useState(false);
  const [diceValue, setDiceValue] = useState(1);

  const boardPositions = generateBoardPositions(BOARD_SIZE);

  const movePlayer = (steps) => {
    setRolling(true);
    let count = 0;
    const interval = setInterval(() => {
      count++;
      setPlayerPosition((prev) => (prev + 1) % TOTAL_SPACES);
      if (count >= steps) {
        clearInterval(interval);
        setRolling(false);
      }
    }, 300);
  };

  const handleRoll = (value) => {
    setDiceValue(value);
    movePlayer(value);
  };

  const current = boardPositions[playerPosition] || { x: 0, y: 0 };

  return (
    <div
      className="flex flex-col items-center justify-center min-h-screen bg-green-900 text-white"
      style={{ overflow: "hidden" }}
    >
      <div
        className="relative"
        style={{
          width: "92vmin",
          height: "92vmin",
          maxWidth: `${BOARD_SIZE}px`,
          maxHeight: `${BOARD_SIZE}px`,
        }}
      >
        {/* Board */}
        <img
          src={boardImage}
          alt="TorahPoly Board"
          className="w-full h-full object-contain rounded-2xl shadow-lg"
        />

        {/* Player token */}
        <div
          style={{
            position: "absolute",
            width: "30px",
            height: "30px",
            backgroundColor: "yellow",
            borderRadius: "50%",
            border: "2px solid black",
            transition: "transform 0.3s linear",
            transform: `translate(${current.x - 15}px, ${current.y - 15}px)`,
          }}
        />
      </div>

      <div className="mt-6 flex flex-col items-center space-y-2">
        <Dice
          disabled={rolling}
          size={80}
          onRoll={handleRoll}
          key={rolling ? "rolling" : "ready"}
        />
        <p className="text-lg">Dice: {diceValue}</p>
        <p className="text-sm text-gray-300">Position: {playerPosition + 1}</p>
      </div>
    </div>
  );
};

export default App;
